mapper.select:
SELECT id, strictness, hide_threshold, sanction_threshold, block_days, updated_at
  FROM ai_moderation_setting
 WHERE id = #{id}

mapper.update:
UPDATE ai_moderation_setting
   SET strictness = #{strictness},
       hide_threshold = #{hideThreshold},
       sanction_threshold = #{sanctionThreshold},
       block_days = #{blockDays}
 WHERE id = #{id}
